INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('pukao-7ec62a85-moex-00052', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-114-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '依國家賠償法規定，下列何種情形並不成立國家賠償責任？', '["職司道路養護之公務員故意怠於履行職務，長期無視道路特定坑洞之存在，致使機車騎士行經該路段滑 倒受傷", "員警進行夜間定時巡邏業務，因過失未留意燈號變換而誤闖紅燈，撞上依燈號指示左轉之民眾車輛", "因過去已有多起溺水意外，主管機關於開放水域設置禁止游泳之警示標語，人民仍執意下水而喪失生命", "高速公路交流道設計與建造有所缺失，匝道彎度明顯過大，導致民眾車輛翻覆而駕駛受傷"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:41+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "417", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00053', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-114-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '有關國家賠償之書面協議先行程序，下列敘述何者錯誤？', '["請求損害賠償時，於協議程序進行中，法院得依聲請為假處分，命賠償義務機關先行賠償損害", "請求損害賠償時，應先以書面向賠償義務機關請求之", "協議成立時，應作成協議書，該項協議書得為執行名義", "賠償義務機關拒絕賠償，請求權人得提起損害賠償之訴"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:41+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "417", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00054', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-113-06dee816', 'sub-pukao-7ec62a85-01', NULL, 'essay', '甲住在老舊公寓的四樓，某日於家中午睡時，驚覺濃煙自門外竄入，發
現門口樓梯間已陷入火海，甲便逃至後陽台，打算攀爬至對面公寓的乙
宅中。甲用拖把木柄敲擊乙宅窗戶，對乙表示上情，要求乙開窗讓他爬
過去，但兩人先前曾有多次口角爭執，乙斷然拒絕甲的請求，甲見火和
濃煙已竄入室內，情急之下，不顧乙的反對，猛力擊碎乙宅後陽台的窗
戶，並攀爬進入乙宅，因而撿回一命。刑法上應如何評價甲之行為？
（30 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:41+00:00", "source_pdf_sha1": "bd6e60965f8b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "420", "s": "1016", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00055', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-113-06dee816', 'sub-pukao-7ec62a85-01', NULL, 'essay', '甲在店家看到老闆乙將新款手機置於櫃臺上，竟趁乙低頭取貨時，一把
抓起桌面上的手機奪門而出，乙跳出追捕未果。甲返家後，想盡快脫手，
便聯絡不知情的友人丙，謊稱自己參加公司尾牙抽中手機，願以市價 9
折的價錢出售，丙信以為真，立即以現金購入該手機。試問甲之刑責？
（35 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:41+00:00", "source_pdf_sha1": "bd6e60965f8b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "420", "s": "1016", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00056', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-113-06dee816', 'sub-pukao-7ec62a85-01', NULL, 'essay', '被告甲因犯貪污罪嫌，經警以現行犯予以逮捕後移送檢察官複訊，甲選
任 A律師為辯護人，檢察官複訊後，認有羈押之必要而向法院聲請羈押，
嗣經法院裁定羈押。試問：辯護人 A律師在檢察官複訊時，有何偵查中
辯護權？檢察官向法院聲請羈押，被告甲與 A 律師有何卷證資訊獲知
權？法院裁定羈押甲後，辯護人 A 律師得否為被告甲之利益而代為抗
告？（35分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:41+00:00", "source_pdf_sha1": "bd6e60965f8b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "420", "s": "1016", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00057', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-113-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '法律規定電子遊戲場業之營業場所應距離學校50公尺，但某直轄市自治條例卻規定為800公尺，依 司法院解釋意旨，下列敘述何者正確？', '["該自治條例無效，因違反法律優位原則", "該自治條例無效，因違反法律保留原則", "該自治條例有效，因後法優先於前法", "該自治條例有效，因地方有自治權限"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:42+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "420", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00058', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-113-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '下列何者須以法律或法律明確授權之命令為依據始得為之？', '["開放公共空間供街頭藝人展演", "命法定傳染病之確診者居家隔離", "興建橋樑並提供公用", "提供空氣品質預報"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:42+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "420", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00059', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-113-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '有關溯及既往與信賴保護原則之敘述，下列何者正確？', '["基於信賴保護原則，法規之適用均不得溯及既往", "真正溯及既往係指新制定之法規，適用於該法規生效前已完結之法律事實", "不真正溯及既往係指新制定之法規，僅適用於該法規生效後發生之法律事實", "不真正溯及既往之法規，不用考量人民對於舊法是否有值得保護之信賴"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:42+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "420", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00060', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-113-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '教師及學校之教育或管理措施，即使構成權利之侵害，學生得據以提起行政爭訟請求救濟，但法院及 其他行政爭訟機關應予教師及學校較高之尊重。此屬下列何種概念？', '["行政保留", "裁量餘地", "專業判斷餘地", "法規制定裁量"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:42+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "420", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
